package main

import "fmt"

func Greeting(name string) string {
	return "Hello, " + name
}

func main() {
	fmt.Println(Greeting("Go"))
}

package main

import "testing"

func TestGreeting(t *testing.T) {
	if Greeting("Codeleon") != "Hello, Codeleon" {
		t.Fatal("unexpected greeting")
	}
}
